use rand::Rng;

use crate::ir::ids::ProductionId;

use super::MutationMeta;

/// A tape byte slice extracted from a corpus entry, associated with a specific production.
///
/// Stored in [`FragmentDb`] and used by splice mutations to replace a production's tape region
/// with a fragment from another corpus entry that was generated by the same production.
#[derive(Debug, Clone)]
pub struct TapeFragment {
    pub tape_bytes: Vec<u8>,
    pub subtree_size: u32,
}

/// Reservoir-sampled pool of tape fragments indexed by `ProductionId`.
///
/// As corpus entries are ingested, their tape regions are decomposed per-production and stored
/// here. Each production maintains up to `max_fragments_per_production` fragments, selected via
/// reservoir sampling so that the pool remains bounded regardless of corpus size. Splice
/// mutations draw from this pool to recombine tape regions across corpus entries.
pub struct FragmentDb {
    pools: Vec<Vec<TapeFragment>>,
    max_fragments_per_production: usize,
}

impl FragmentDb {
    pub fn new(n_productions: usize, max_per_production: usize) -> Self {
        Self {
            pools: vec![Vec::new(); n_productions],
            max_fragments_per_production: max_per_production,
        }
    }

    /// Decompose a corpus entry's tape into per-production fragments and add them to the pool.
    ///
    /// For each `TapeMap` entry, extracts the corresponding tape byte slice and either appends
    /// it to the production's pool (if under capacity) or replaces a random existing fragment
    /// (reservoir sampling).
    pub fn ingest(&mut self, tape: &[u8], meta: &MutationMeta, rng: &mut impl Rng) {
        for entry in &meta.tape_map.entries {
            let pid = entry.production_id.0 as usize;
            if pid >= self.pools.len() {
                continue;
            }
            let end = entry.tape_offset + entry.tape_len;
            if end > tape.len() {
                continue;
            }
            let pool = &mut self.pools[pid];
            let subtree_size = meta.subtree_sizes[entry.node_id.0 as usize];
            if pool.len() < self.max_fragments_per_production {
                pool.push(TapeFragment {
                    tape_bytes: tape[entry.tape_offset..end].to_vec(),
                    subtree_size,
                });
            } else {
                let idx = rng.gen_range(0..pool.len());
                pool[idx] = TapeFragment {
                    tape_bytes: tape[entry.tape_offset..end].to_vec(),
                    subtree_size,
                };
            }
        }
    }

    /// Return a random fragment for the given production, or `None` if the pool is empty.
    pub fn sample(&self, prod: ProductionId, rng: &mut impl Rng) -> Option<&TapeFragment> {
        let pool = &self.pools[prod.0 as usize];
        if pool.is_empty() {
            None
        } else {
            Some(&pool[rng.gen_range(0..pool.len())])
        }
    }

    pub fn pool_len(&self, prod: ProductionId) -> usize {
        self.pools[prod.0 as usize].len()
    }
}
